import { Directive, Input } from '@angular/core';
import {
  AbstractControl,
  NG_VALIDATORS,
  ValidationErrors,
} from '@angular/forms';

@Directive({
  selector: '[forbiddenSame]',
  providers: [
    {
      provide: NG_VALIDATORS,
      useExisting: ForbiddenSameValidatorDirective,
      multi: true,
    },
  ],
})
export class ForbiddenSameValidatorDirective {
  @Input('forbiddenSame') compareValue: any;

  validate(control: AbstractControl): ValidationErrors | null {
    return this.compareValue === control.value ? { isSame: true } : null;
  }
}
