import { coerceNumberProperty } from '@angular/cdk/coercion';
import { Directive, Input } from '@angular/core';
import { AbstractControl, NG_VALIDATORS, ValidationErrors, Validators } from '@angular/forms';



@Directive({
  selector: '[ngModel][max], input[max]',
  providers: [{
    provide: NG_VALIDATORS,
    useExisting: MaxValidatorDirective,
    multi: true
  }]
})
export class MaxValidatorDirective {
  @Input('max') set min(value: string | number) {
    this.maxValue = coerceNumberProperty(value);
  }
  
  private maxValue: number;

  validate(control: AbstractControl): ValidationErrors | null {
    return Validators.max(this.maxValue)(control);
  }
}
