import { coerceNumberProperty } from '@angular/cdk/coercion';
import { Directive, Input } from '@angular/core';
import { AbstractControl, NG_VALIDATORS, ValidationErrors, Validators } from '@angular/forms';



@Directive({
  selector: '[ngModel][min], input[min]',
  providers: [{
    provide: NG_VALIDATORS,
    useExisting: MinValidatorDirective,
    multi: true
  }]
})
export class MinValidatorDirective {
  @Input('min') set min(value: string | number) {
    this.minValue = coerceNumberProperty(value);
  }
  
  private minValue: number;

  validate(control: AbstractControl): ValidationErrors | null {
    return Validators.min(this.minValue)(control);
  }
}
